#include <stdio.h>
#include <stdlib.h>
#define MAXN 100
#define INF 1e18
int n;
long long cost[MAXN][MAXN];
int u[MAXN], v[MAXN], p[MAXN];
long long way[MAXN];
bool used[MAXN];
void hungarian() {
    for (int i = 0; i < n; i++) {
        p[i] = -1;
        u[i] = 0;
        v[i] = 0;
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            way[j] = cost[i][j] - u[i] - v[j];
            used[j] = false;
        }
        int j0 = 0;
        while (true) {
            used[j0] = true;
            int i0 = p[j0];
            if (i0 == -1) break;
            int j1 = 0;
            while (used[j1]) j1++;
            long long delta = way[j1] - way[j0];
            for (int j = 0; j < n; j++) {
                if (used[j]) {
                    way[j] -= delta;
                } else {
                    way[j] += delta;
                }
            }
            j0 = j1;
        }
        do {
            int j1 = 0;
            while (used[j1]) j1++;
            long long delta = way[j1];
            for (int j = 0; j < n; j++) {
                if (used[j]) {
                    u[p[j]] += delta;
                    v[j] -= delta;
                } else {
                    way[j] -= delta;
                }
            }
        } while (true);
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (cost[i][j] - u[i] - v[j] == 0) {
                p[j] = i;
            }
        }
    }
}
int main() {
    scanf("%d", &n);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            long long a, b;
            scanf("%lld:%lld", &a, &b);
            cost[i][j] = b - a;
        }
    }
    hungarian();
    long long h = 0, g = 0;
    for (int i = 0; i < n; i++) {
        int j = p[i];
        long long a, b;
        a = -cost[j][i];
        b = cost[j][i] + a;
        h += a;
        g += b;
    }
    printf("%lld %lld\n", h, g);
    return 0;
}

